// Extractor robusto que busca en múltiples campos

function extractCsvUrl(data) {
  // Campos posibles donde puede estar el log
  const possibleFields = ['output', 'log', 'message', 'text', 'body', 'response', 'data'];

  // Buscar en cada campo posible
  for (const field of possibleFields) {
    const content = data[field];
    if (content && typeof content === 'string') {
      const match = content.match(/CSV saved at\s+(https?:\/\/[^\s]+\.csv)/i);
      if (match) {
        return match[1];
      }
    }
  }

  // Si no encuentra, buscar en todo el objeto convertido a string
  const fullText = JSON.stringify(data);
  const match = fullText.match(/CSV saved at\s+(https?:\/\/[^\s]+\.csv)/i);

  return match ? match[1] : null;
}

// Procesar todos los items
return $input.all().map((item, index) => {
  const csvUrl = extractCsvUrl($input.first().json.output);

  return {
    json: {
      itemIndex: index,
      csvUrl: csvUrl,
      found: csvUrl !== null,
      originalData: item.json // Mantener datos originales
    }
  };
});

