      videosList: []
    };
  }

  const currentProfile = profileStats[data.username];

  // ========== 1. PROCESS LATEST POSTS ==========
  if (data.latestPosts && Array.isArray(data.latestPosts)) {
    console.log(`📋 latestPosts found: ${data.latestPosts.length}`);

    for (const post of data.latestPosts) {
      currentProfile.totalPosts++;

      // Count by type
      if (post.type === 'Video') currentProfile.videos++;
      else if (post.type === 'Image') currentProfile.images++;
      else if (post.type === 'Sidecar') currentProfile.carousels++;

      // 🎥 FILTER ONLY VIDEOS
      if (post.type === 'Video') {
        const views = post.videoViewCount || 0;
        const likes = post.likesCount || 0;

        // Accumulate stats for this profile
        if (views > 0) {
          currentProfile.totalViews += views;
          currentProfile.videosWithViews++;
        }
        currentProfile.totalLikes += likes;

        const videoData = {
          source: 'latestPosts',
          type: post.type,
          id: post.id,
          shortCode: post.shortCode,
          url: post.url,
          caption: post.caption || 'No description',
          likes: post.likesCount !== null ? post.likesCount : 'Not available',
          comments: post.commentsCount || 0,
          views: post.videoViewCount || 'Not available',
          hashtags: post.hashtags || [],
          mentions: post.mentions || [],
          timestamp: post.timestamp || 'Not available',
          username: post.ownerUsername,
