          dimensions: {
            height: post.dimensionsHeight,
            width: post.dimensionsWidth
          },
          videoUrl: post.videoUrl || 'Not available',
          displayUrl: post.displayUrl
        };

        results.push(videoData);
        currentProfile.videosList.push(videoData);
      }
    }
