  if (data.latestIgtvVideos && Array.isArray(data.latestIgtvVideos)) {
    console.log(`📺 IGTV Videos found: ${data.latestIgtvVideos.length}`);

    for (const video of data.latestIgtvVideos) {
      currentProfile.igtvVideos++;

      const views = video.videoViewCount || 0;
      const likes = video.likesCount || 0;

      // Accumulate stats for this profile
      if (views > 0) {
        currentProfile.totalViews += views;
        currentProfile.videosWithViews++;
      }
      currentProfile.totalLikes += likes;

      const videoData = {
        source: 'IGTV',
        type: video.type,
        id: video.id,
        shortCode: video.shortCode,
        url: video.url,
        title: video.title || 'No title',
        caption: video.caption || 'No description',
        likes: video.likesCount !== null ? video.likesCount : 'Not available',
        comments: video.commentsCount || 0,
        views: video.videoViewCount || 'Not available',
        duration: video.videoDuration ? `${video.videoDuration}s` : 'Not available',
        hashtags: video.hashtags || [],
        mentions: video.mentions || [],
