const items = $input.all().map(item => {
  try {
    let content = item.json.message.content;

    // Remover bloques de código markdown si existen
    if (content.includes('```')) {
      content = content
        .replace(/```json\s*/gi, '')
        .replace(/```\s*/g, '')
        .trim();
    }

    // Limpiar saltos de línea literales
    content = content.replace(/\\n/g, ' ');

    // Intentar parsear directamente primero
    try {
      const data = JSON.parse(content);
      return {
        category: data.primary_category || null,
        username: data.username || null,
        bio: data.bio || null
      };
    } catch (e) {
      // Si falla, intentar arreglar comillas problemáticas en los valores
      // Reemplaza comillas dobles dentro de los valores por comillas simples
      content = content.replace(/"([^"]*)":\s*"([^"]*)"/g, (match, key, value) => {
        // Reemplazar comillas dobles internas por comillas simples
        const cleanValue = value.replace(/"/g, "'");
        return `"${key}": "${cleanValue}"`;
      });

      const data = JSON.parse(content);
      return {
        category: data.primary_category || null,
        username: data.username || null,
        bio: data.bio || null
      };
    }
  } catch (error) {
    // Fallback: extraer con regex si todo falla
    const content = item.json.message.content;

    const categoryMatch = content.match(/"primary_category":\s*"([^"]+)"/);
    const usernameMatch = content.match(/"username":\s*"([^"]+)"/);
    const bioMatch = content.match(/"bio":\s*"([\s\S]*?)"\s*\n?\}/);

    return {
      category: categoryMatch ? categoryMatch[1] : null,
      username: usernameMatch ? usernameMatch[1] : null,
      bio: bioMatch ? bioMatch[1].replace(/\\n/g, ' ').replace(/"/g, "'") : null,
      _extracted_via: 'regex_fallback'
    };
  }
});
return items;

// Función para extraer email de un texto
function extractEmail(text) {
  if (!text) return "";

  // Regex robusto para detectar emails en cualquier parte del texto
  const emailRegex = /([a-zA-Z0-9._+-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9._-]+)/gi;

  // Buscar todos los emails en el texto
  const matches = text.match(emailRegex);

  // Si encuentra email(s), retornar el primero, sino retornar ""
  return matches && matches.length > 0 ? matches[0] : "";
}

